## Objective

Create `apps/server/src/services/extensions/extension-server-api-factory.ts` — a factory function that builds a `DataProviderContext` instance for each server-side extension. This context provides secrets, storage, scheduling, and SSE event emission.

## Implementation Steps

### 1. Create the factory file

New file: `apps/server/src/services/extensions/extension-server-api-factory.ts`

```typescript
import type { DataProviderContext } from '@dorkos/extension-api/server';
import { ExtensionSecretStore } from '@dorkos/shared/extension-secrets';
import { eventFanOut } from '../core/event-fan-out.js';
import fs from 'fs/promises';
import path from 'path';
import { logger } from '../../lib/logger.js';

/** Minimum scheduling interval in seconds (prevents tight loops). */
const MIN_INTERVAL_SECONDS = 5;

/** Internal extension of DataProviderContext with cleanup tracking. */
export interface DataProviderContextInternal extends DataProviderContext {
  /** Get all registered scheduled task cleanup functions. */
  _getScheduledCleanups(): Array<() => void>;
}

interface CreateContextDeps {
  extensionId: string;
  extensionDir: string;
  dorkHome: string;
  getCwd: () => string | null;
}

/**
 * Build a DataProviderContext for a server-side extension.
 *
 * Each extension gets its own isolated context with:
 * - Scoped encrypted secret store
 * - Shared data storage (same path as client loadData/saveData)
 * - Interval-based scheduler with 5-second floor
 * - SSE event emitter via EventFanOut
 *
 * @param deps - Extension identity and directory info
 * @returns DataProviderContext with internal cleanup tracking
 */
export function createDataProviderContext(
  deps: CreateContextDeps
): DataProviderContextInternal {
  const scheduledCleanups: Array<() => void> = [];
  const { extensionId, extensionDir, dorkHome, getCwd } = deps;

  const secrets = new ExtensionSecretStore(extensionId, dorkHome);

  const storage = {
    async loadData<T = unknown>(): Promise<T | null> {
      const dataPath = resolveDataPath(extensionId, dorkHome, getCwd);
      try {
        const raw = await fs.readFile(dataPath, 'utf-8');
        return JSON.parse(raw) as T;
      } catch {
        return null;
      }
    },
    async saveData<T = unknown>(data: T): Promise<void> {
      const dataPath = resolveDataPath(extensionId, dorkHome, getCwd);
      await fs.mkdir(path.dirname(dataPath), { recursive: true });
      const tempPath = dataPath + '.tmp';
      await fs.writeFile(tempPath, JSON.stringify(data, null, 2), 'utf-8');
      await fs.rename(tempPath, dataPath);
    },
  };

  function schedule(intervalSeconds: number, fn: () => Promise<void>): () => void {
    const clamped = Math.max(intervalSeconds, MIN_INTERVAL_SECONDS);
    const interval = setInterval(() => {
      fn().catch((err) => {
        logger.error(`[ext:${extensionId}] Scheduled task error:`, err);
      });
    }, clamped * 1000);
    const cancel = () => clearInterval(interval);
    scheduledCleanups.push(cancel);
    return cancel;
  }

  function emit(event: string, data: unknown): void {
    eventFanOut.broadcast(`ext:${extensionId}:${event}`, data);
  }

  return {
    secrets,
    storage,
    schedule,
    emit,
    extensionId,
    extensionDir,
    _getScheduledCleanups: () => [...scheduledCleanups],
  };
}

/**
 * Resolve the data.json path for an extension.
 * Uses global path by default, local path if a CWD is active.
 */
function resolveDataPath(
  extensionId: string,
  dorkHome: string,
  getCwd: () => string | null
): string {
  // Always use global path for server-side context (server doesn't track per-extension scope)
  return path.join(dorkHome, 'extension-data', extensionId, 'data.json');
}
```

