## Objective

Mount a dynamic route delegation middleware that forwards requests from `/api/ext/:id/*` to the corresponding extension's Express router. Also add an SSE endpoint for extension-specific events.

## Implementation Steps

### 1. Create route delegation middleware

Create a new file `apps/server/src/routes/extension-delegation.ts` (keeping the extension management routes in the existing `extensions.ts` file separate from the runtime delegation):

```typescript
/**
 * Dynamic route delegation for server-side extensions.
 *
 * Forwards /api/ext/:id/* to the extension's registered Express router.
 * Separate from /api/extensions/ (lifecycle management) to prevent namespace collision.
 *
 * @module routes/extension-delegation
 */
import { Router, type Request, type Response, type NextFunction } from 'express';
import type { ExtensionManager } from '../services/extensions/extension-manager.js';
import { logger } from '../lib/logger.js';

/** Validates extension IDs match the manifest schema pattern. */
const SAFE_EXT_ID = /^[a-z0-9][a-z0-9-]*$/;

/**
 * Create the extension delegation router for /api/ext/:id/*.
 *
 * @param extensionManager - ExtensionManager for router lookup
 * @returns Router that delegates to extension-registered routes
 */
export function createExtensionDelegationRouter(
  extensionManager: ExtensionManager
): Router {
  const router = Router();

  // /api/ext/:id/* -- Delegate to extension's server-registered router
  router.use('/:id', (req: Request, res: Response, next: NextFunction) => {
    const { id } = req.params;
    if (!SAFE_EXT_ID.test(id)) {
      return res.status(400).json({ error: 'Invalid extension ID' });
    }

    const extRouter = extensionManager.getServerRouter(id);
    if (!extRouter) {
      return res.status(404).json({
        error: `Extension '${id}' has no server routes`,
      });
    }

    extRouter(req, res, next);
  });

  return router;
}
```

### 2. Mount in the Express app

In the main Express app setup (likely `apps/server/src/index.ts` or a route registration file), mount the delegation router:

```typescript
