  // Handle proxy-only extensions (dataProxy without server.ts)
  if (record.hasDataProxy && !record.hasServerEntry) {
    await this.shutdownServer(id);
    const proxyRouter = createProxyRouter(id, record.manifest.dataProxy!, this.dorkHome);
    this.serverExtensions.set(id, {
      extensionId: id,
      router: proxyRouter,
      cleanup: null,
      scheduledCleanups: [],
    });
    logger.info(`[Extensions] Proxy router mounted for ${id}`);
    return { ok: true };
  }

  // Existing server.ts handling...
  // If extension has BOTH server.ts AND dataProxy, mount proxy alongside:
  // After the register call, mount proxy at /proxy/* on the same router
  if (record.hasDataProxy && record.manifest.dataProxy) {
    const proxyRouter = createProxyRouter(id, record.manifest.dataProxy, this.dorkHome);
    // Mount proxy routes on the extension's router
    router.use(proxyRouter);
  }
  // ... rest of existing code
}
