/** Client-side template for data-provider extensions — fetches from server endpoint. */
function generateDataProviderClientTemplate(name: string, description: string): string {
  const pascalName = toPascalCase(name);
  const titleName = toTitleCase(name);
  const desc = description || 'A data provider extension.';

  return `// ${name} — DorkOS Extension (Client)
// ${desc}
//
// This extension fetches data from its server-side endpoint.
// Server code lives in server.ts alongside this file.

import type { ExtensionAPI } from '@dorkos/extension-api';

function ${pascalName}Section() {
  const [data, setData] = React.useState(null);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    fetch('/api/ext/${name}/data')
      .then((r) => r.json())
      .then(setData)
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ padding: '16px' }}>Loading...</div>;

  return (
    <div style={{ padding: '16px', border: '1px solid var(--border)', borderRadius: '12px' }}>
      <h3 style={{ margin: '0 0 8px 0', fontSize: '14px', fontWeight: 600 }}>
        ${titleName}
      </h3>
      <pre style={{ margin: 0, fontSize: '12px', color: 'var(--muted-foreground)' }}>
        {JSON.stringify(data, null, 2)}
      </pre>
    </div>
  );
}

export function activate(api: ExtensionAPI): void {
  api.registerComponent('dashboard.sections', '${name}-section', ${pascalName}Section, {
    priority: 50,
  });
}
`;
}
